你正在开发电商秒杀场景的商品库存扣减核心模块，需满足以下业务约束与技术要求：1. 基础规则：商品初始库存为1000件，单次扣减最小单位为1件，最大单次扣减上限为10件；单用户对同一商品单日累计扣减上限为5件，扣减后库存不允许为负；2. 并发控制：采用Redis分布式锁实现并发控制，锁的过期时间设置为3秒，单次扣减逻辑的最大执行超时时间设置为2秒；3. 异常处理要求：扣减过程中若出现库存不足、锁获取失败、网络异常、执行超时等场景，需回滚所有已修改的临时状态，记录包含请求ID、用户ID、商品ID、异常详情的错误日志，返回对应业务错误码；4. 数据一致性要求：库存扣减需保证原子性，避免超卖、重复扣减问题。当前实现的Python代码片段如下：```python
import redis
import time
import logging
from datetime import datetime

# 初始化Redis连接
r = redis.Redis(host='localhost', port=6379, db=0)
# 单日用户扣减计数本地缓存，key格式为user:day:count:{user_id}:{product_id}
user_day_count_cache = {}

def deduct_stock(user_id: int, product_id: int, count: int) -> dict:
    # 边界校验1：单次扣减数量范围
    if count < 1 or count > 10:
        return {"code": 4001, "msg": "单次扣减数量需在1-10之间"}

    # 边界校验2：单日扣减次数限制
    today = datetime.now().strftime("%Y-%m-%d")
    cache_key = f"user:day:count:{user_id}:{product_id}"
    if cache_key in user_day_count_cache and user_day_count_cache[cache_key] >= 5:
        return {"code": 4002, "msg": "单日扣减次数已达上限"}

    # 获取分布式锁，过期时间3秒
    lock_key = f"stock:lock:{product_id}"
    lock_value = f"{user_id}:{time.time()}"
    # 尝试获取锁，最多重试2次，每次间隔0.1秒
    for _ in range(2):
        if r.set(lock_key, lock_value, nx=True, ex=3):
            break
        time.sleep(0.1)
    else:
        logging.error(f"用户{user_id}扣减商品{product_id}锁获取失败，请求ID：{request_id}")
        return {"code": 4003, "msg": "系统繁忙，请稍后重试"}

    try:
        # 校验库存是否充足
        stock_key = f"stock:{product_id}"
        current_stock = int(r.get(stock_key) or 0)
        if current_stock < count:
            return {"code": 4004, "msg": "库存不足"}

        # 扣减库存
        r.decrby(stock_key, count)

        # 更新单日扣减计数
        if cache_key not in user_day_count_cache:
            user_day_count_cache[cache_key] = 0
        user_day_count_cache[cache_key] += count

        # 模拟后续业务逻辑（如生成订单），超时时间2秒
        time.sleep(2.5) # 模拟业务执行超时

        return {"code": 0, "msg": "扣减成功", "剩余库存": int(r.get(stock_key))}
    except Exception as e:
        logging.error(f"扣减异常，用户{user_id}，商品{product_id}，异常：{str(e)}")
        # 回滚库存
        r.incrby(stock_key, count)
        # 回滚单日计数
        user_day_count_cache[cache_key] -= count
        return {"code": 5000, "msg": "系统异常"}
    finally:
        # 释放分布式锁
        r.delete(lock_key)
